class Solution {
    public int[][] validArrangement(int[][] pairs) {
        int[][] result = new int[pairs.length][2];
        for (int i = 0; i < pairs.length; i++) {
            result[i][0] = pairs[i][0];
            result[i][1] = pairs[i][1];
        }
        Arrays.sort(result);
        int j = 0;
        for (int i = 0; i < pairs.length; i++) {
            while (result[j][0] != pairs[i][0] || result[j][1] != pairs[i][1]) {
                j++;
            }
            result[i][0] = result[j-1][1];
            result[i][1] = result[j][0];
        }
        return result;
    }
}
